use yii\base\BaseObject;
use yii\queue\RetryableJobInterface;

class ElearningStoreQueue extends BaseObject implements RetryableJobInterface
{

    public $data;

    public function __construct($data)
    {
        $this->data = $data;
    }

    public function execute($queue)
    {
        if (!empty($this->data['id'])) {
            $elearing = ElearningStoreCourse::findOne($this->data['id']);
            if (!empty($elearing)) {
                $store = ElearningStore::findOne($elearing->store_id);
                if ($store->type == ElearningStore::TIKTOK) {
                    $this->tiktokQueue($elearing);
                } else if ($store->type == ElearningStore::SALEKIT) {
                    $this->salekitQueue($elearing, $store);
                }
            }
        }
        if (!empty($this->data['elearning_store_order_id'])) {
            $elearningOrder = ElearningStoreOrder::findOne($this->data['elearning_store_order_id']);
            if (!empty($elearningOrder)) {
                $store = ElearningStore::findOne($elearningOrder->store_id);
                if ($store->type == ElearningStore::SALEKIT) {
                    $this->salekitOrderQueue($elearningOrder, $store);
                }
            }
        }
    }

    public function tiktokQueue($elearing)
    {
        if ($elearing->status == false) {
            $store = ElearningStore::findOne($elearing->store_id);
            $course = MCourse::findOne($elearing->course_id);
            $image = base64_encode(file_get_contents($course->image_ecommerce));
            $tiktok = new TiktokShop();
            $imageTiktok = $tiktok->uploadImage($store->tiktok_access_token, $store->tiktok_shop_id, $image)['img_id'];
            $request = [
                'category_id' => (string)$store->tiktok_category_id,
                'description' => $course->Description,
                'images' => [
                    (object)['id' => (string)$imageTiktok]
                ],
                'is_cod_open' => true,
                'package_weight' => '0.1',
